import axios from 'axios';
import { STATUS } from '../../utils/constants';
import { notifyResponseMessage } from '../commoncomponent/NotificationComponent/notifyResponseMessage';
import {BASE_PATH_APIS} from '../../utils/constants';

class AWBGenerationService {

    async fetchAWBPartyConf(pageNumber, recordPerPage) {
        try {
            const response = await axios.get(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/get/awb_party_list',{
                params: {
                            pageNumber: pageNumber,
                            recordPerPage:recordPerPage
                        }
            })
            return response;
        } catch (error) {
            notifyResponseMessage(STATUS.ERROR, error);
        }
        return null;
    }

    async searchAWBPartyListByPartyCode(partyCodes,pageNumber, recordPerPage) {
        const response = await axios.get(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/search/awb_party_list', {
            params: {
                partyCodes : partyCodes,
                pageNumber: pageNumber,
                recordPerPage:recordPerPage
            }
        })
        .then(response => {
            return response;
        })
        .catch(error => {
            if(error.response && error.response.status === 400){
                return error.response;
        }
            return [];
        })
        return response;

    }


    async fetchAWBDefaultDetails() {
        try {
            const response = await axios.get(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/get/default_awb_conf');
            return response;
        } catch (error) {
            notifyResponseMessage(STATUS.ERROR, error);
        }
        return null;
    }

    async saveAWBDefaultDetails(awbDefaultDetails) {
        try {
            const response = await axios.post(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/addOrUpdate/default_awb_conf', awbDefaultDetails);
            return response;
        } catch (error) {
            notifyResponseMessage(STATUS.ERROR, error);
        }
        return null;
    }

    async saveAWBPartyConf(awbPartyConf) {
        try {
            const response = await axios.post(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/addOrUpdate/awb_party_conf', awbPartyConf);
            return response;
        } catch (error) {
            notifyResponseMessage(STATUS.ERROR, error);
        }
        return null;
    }

    async deleteAWBPartyConf(id) {
        try {
            const response = await axios.post(BASE_PATH_APIS.basePathForAPIS+`/app/rest/label_generation/delete/awb_party_conf?awbPartyMasterId=${id}`);
            return response;
        } catch (error) {
            notifyResponseMessage(STATUS.ERROR, error);
        }
        return null;
    }

    async fetchAllPartyMaster() {
        try {
            const response = await axios.get(BASE_PATH_APIS.basePathForAPIS+'/app/rest/label_generation/getAll_party_master');
            return response;
        } catch (error) {
            notifyResponseMessage(STATUS.ERROR, error);
        }
        return null;
    }

}

export const awbGenerationService = new AWBGenerationService();
